/** @jsxImportSource @emotion/react */
import { css, useTheme } from '@emotion/react';

function Card({ elevated = false }) {
  const theme = useTheme();
  return (
    <div css={css`
      padding: ${theme.spacing.md};
      border-radius: ${theme.radii.lg};
      ${elevated && `box-shadow: ${theme.shadows.md};`}
    `}>
      content
    </div>
  );
}

const base = css`display: flex; align-items: center; gap: 0.5rem;`;
const interactive = css`cursor: pointer; transition: transform 0.2s; &:hover { transform: translateY(-2px); }`;

const InteractiveCard = styled.div`${base} ${interactive} padding: 1rem;`;
